import { campaigns, magazines, stores } from "@/data/content";

export async function getCampaigns() {
  return campaigns.filter((item) => item.active).sort((a, b) => a.order - b.order);
}
export async function getStores() { return stores; }
export async function getMagazines() { return magazines; }

